function byteLength(t){return 2*t.length}function toString(t){const e=t.byteLength;let n="";for(let r=0;r<e-1;r+=2)n+=String.fromCharCode(t[r]+256*t[r+1]);return n}function write(t,e){const n=t.byteLength;let r=n;for(let n=0;n<e.length&&!((r-=2)<0);++n){const r=e.charCodeAt(n),o=r>>8,g=r%256;t[2*n]=g,t[2*n+1]=o}return n}module.exports={byteLength:byteLength,toString:toString,write:write};